import React, { useEffect, useState } from "react";
import { Table, Button, Input, Tooltip, Avatar } from "antd";
import {
  Trash2,
  Plus,
  Search,
  Pencil,
  BookOpen,
  Newspaper,
  FileText,
  Activity,
  History,
} from "lucide-react";
import { Link, useLocation } from "react-router-dom";
import { useDispatch, useSelector } from "react-redux";
import { deleteABlog, getBlogs, resetState } from "../features/blogs/blogSlice";
import CustomModal from "../components/CustomModal";
import { delImg } from "../features/upload/uploadSlice";

const Bloglist = () => {
  const [open, setOpen] = useState(false);
  const [blogId, setblogId] = useState("");
  const [searchText, setSearchText] = useState("");

  const showModal = (e) => {
    setOpen(true);
    setblogId(e);
  };

  const hideModal = () => {
    setOpen(false);
  };

  const dispatch = useDispatch();
  const location = useLocation();
  const pathParts = location.pathname.split("/");
  const basePath = pathParts[1] || "admin";

  useEffect(() => {
    dispatch(resetState());
    dispatch(getBlogs());
  }, [dispatch]);

  const getBlogState = useSelector((state) => state.blogs.blogs);

  const columns = [
    {
      title: "Index ID",
      dataIndex: "key",
      render: (text) => (
        <span className="font-black text-[11px] text-slate-400 bg-slate-50 px-3 py-1.5 rounded-lg border border-slate-100 uppercase tracking-widest">
          #ART-{String(text).padStart(3, "0")}
        </span>
      ),
    },
    {
      title: "Content Profile",
      dataIndex: "name",
      render: (text, record) => (
        <div className="flex items-center gap-5">
          <div className="relative">
            <Avatar
              size={56}
              src={`https://api.dicebear.com/7.x/initials/svg?seed=${text}&backgroundColor=f1f5f9&textColor=2563eb&bold=true`}
              className="rounded-2xl border-2 border-white shadow-sm ring-1 ring-slate-100"
            />
            <div className="absolute -bottom-1 -right-1 w-5 h-5 bg-emerald-500 rounded-full border-2 border-white" title="Active Status" />
          </div>
          <div className="flex flex-col">
            <span className="vibe-text-primary text-[16px] font-black tracking-tight leading-none mb-1.5">
              {text}
            </span>
            <div className="flex items-center gap-2">
              <span className="vibe-pill vibe-pill-muted">
                Health Bulletin
              </span>
            </div>
          </div>
        </div>
      ),
      sorter: (a, b) => a.name.localeCompare(b.name),
    },
    {
      title: "Segment",
      dataIndex: "category",
      render: (cat) => (
        <div className="flex items-center gap-2">
          <span className="vibe-pill vibe-pill-accent">
            {cat}
          </span>
        </div>
      ),
    },
    {
      title: "Operation Control",
      dataIndex: "action",
      render: (_, record) => (
        <div className="flex items-center gap-3">
          <Link to={`/${basePath}/blog/${record._id}`}>
            <Tooltip title="Edit Manuscript">
              <Button
                type="text"
                icon={<Pencil size={18} />}
                className="vibe-action-btn vibe-action-btn-primary"
              />
            </Tooltip>
          </Link>
          <Tooltip title="Purge Record">
            <Button
              type="text"
              icon={<Trash2 size={18} />}
              onClick={() => showModal(record._id)}
              className="vibe-action-btn vibe-action-btn-danger"
            />
          </Tooltip>
        </div>
      ),
    },
  ];

  const data1 =
    getBlogState
      ?.filter(
        (b) =>
          !searchText ||
          b.title.toLowerCase().includes(searchText.toLowerCase()),
      )
      .map((blog, i) => ({
        key: i + 1,
        _id: blog._id,
        name: blog.title,
        category: blog.category,
      })) || [];

  const deleteBlog = (e) => {
    dispatch(deleteABlog(e));
    setOpen(false);
    setTimeout(() => {
      dispatch(getBlogs());
    }, 100);
  };

  return (
    <div className="space-y-10 pb-20 animate-in fade-in duration-500">
      {/* Header Navigation */}
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-8">
        <div className="space-y-1">
          <div className="flex items-center gap-2 mb-2">
            <div className="h-1 w-6 bg-accent rounded-full" />
            <span className="vibe-text-accent text-[11px] font-black uppercase tracking-widest">Medical Intelligence</span>
          </div>
          <h1 className="vibe-h1">
            Knowledge Base<span className="text-accent">.</span>
          </h1>
          <p className="vibe-text-muted text-[15px] font-bold max-w-lg">
            Manage and curate high-fidelity medical articles and wellness guides.
          </p>
        </div>
        
        <div className="flex flex-col sm:flex-row items-center gap-4 w-full lg:w-auto">
          <div className="relative w-full sm:w-80 group">
            <Search
              className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-accent transition-colors"
              size={18}
            />
            <input
              type="text"
              placeholder="Filter by title..."
              className="vibe-input pl-12"
              onChange={(e) => setSearchText(e.target.value)}
            />
          </div>
          <Link to={`/${basePath}/blog`} className="w-full sm:w-auto">
            <button className="vibe-btn vibe-btn-primary h-14 px-8 uppercase tracking-widest flex items-center justify-center gap-3">
              <Plus size={20} strokeWidth={3} /> Issue Article
            </button>
          </Link>
        </div>
      </div>

      <div className="vibe-card !p-0 overflow-hidden">
        <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between p-8 border-b border-white/5 bg-white/5 dark:bg-white/5 gap-4">
          <div className="flex items-center gap-4">
            <div className="vibe-icon-box vibe-icon-box-primary">
              <Newspaper size={20} />
            </div>
            <div>
              <h3 className="vibe-text-primary text-[18px] font-black leading-none">Manuscript Registry</h3>
              <p className="vibe-text-muted text-[12px] font-bold mt-1 uppercase tracking-wider">
                Index: <span className="text-accent">{data1.length} Articles</span>
              </p>
            </div>
          </div>
          <div className="flex items-center gap-6">
             <div className="flex flex-col text-right">
                <span className="vibe-text-muted text-[11px] font-black uppercase tracking-widest mb-1">Health Status</span>
                <span className="text-[12px] font-black text-emerald-500 flex items-center gap-1.5 justify-end">
                   <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse" />
                   Fully Optimized
                </span>
             </div>
          </div>
        </div>

        <Table
          columns={columns}
          dataSource={data1}
          pagination={{
            pageSize: 10,
            className: "px-8 py-6",
            position: ["bottomRight"]
          }}
          className="vibe-table"
        />
      </div>

      <CustomModal
        hideModal={hideModal}
        open={open}
        performAction={() => deleteBlog(blogId)}
        title={
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-xl bg-red-50 text-red-600 flex items-center justify-center">
               <Trash2 size={20} />
            </div>
            <span className="font-black text-slate-900">Confirm Deletion</span>
          </div>
        }
        content={
          <p className="text-slate-400 font-bold ml-13">
             This operation will permanently purge the record from the medical vault. 
             <span className="text-red-500 mt-2 block">This action is irreversible.</span>
          </p>
        }
      />
    </div>
  );
};

export default Bloglist;
